import{_ as t,o as i,c as o,ag as a}from"./chunks/framework.BZohXCq9.js";const P=JSON.parse('{"title":"ModLink Studio 文档总览","description":"","frontmatter":{"layout":"home","hero":{"name":"ModLink Studio","text":"设备接入、多模态采集与展示的文档站","tagline":"了解 0.2.0 的 PyPI 发布口径、driver 契约、纯 Python runtime 和双 UI / host 方向","actions":[{"theme":"brand","text":"开始安装","link":"/install"},{"theme":"alt","text":"查看 SDK","link":"/sdk"}]},"features":[{"icon":"📦","title":"PyPI 安装","details":"0.2.0 正式发布后将通过 PyPI 分发；发布前会先完成一次 TestPyPI rehearsal。"},{"icon":"🔌","title":"Driver 接入","details":"外部 driver 优先依赖仓库内的 SDK 契约，通过 modlink.drivers entry point 被宿主发现。"},{"icon":"🧠","title":"纯 Python Runtime","details":"SDK 与 Core 已从 Qt 运行时语义中拆开，宿主围绕统一流模型和采集后端工作。"},{"icon":"🖥️","title":"双 UI / Host 方向","details":"0.2.0 继续保留 Qt Widgets 宿主，同时推进 QML UI 和 FastAPI host，为后续 HTML / Web UI 做准备。"},{"icon":"⚠️","title":"0.2.0 破坏升级","details":"0.2.0 不兼容 0.1.x 的 Qt-style driver API；当前版本边界是稳定采集、录制和保存。"}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1775476775000}'),d={name:"index.md"};function l(r,e,n,s,c,h){return i(),o("div",null,[...e[0]||(e[0]=[a('<div style="height:1rem;"></div><h1 id="modlink-studio-文档总览" tabindex="-1">ModLink Studio 文档总览 <a class="header-anchor" href="#modlink-studio-文档总览" aria-label="Permalink to &quot;ModLink Studio 文档总览&quot;">​</a></h1><p>当前文档以 <code>0.2.0</code> 主线为准。这里描述的是 <code>0.2.0</code> 的目标发布状态，而不是 <code>0.1.x</code> 的旧行为：</p><ul><li><code>modlink_sdk</code> / <code>modlink_core</code> 已经是纯 Python runtime</li><li><code>0.2.0</code> 不兼容 <code>0.1.x</code> 的 Qt-style driver API</li><li>UI 当前保持 Qt Widgets 与 QML 两条桌面路线并行</li><li>FastAPI host 已建立服务化边界，用于后续 HTML / Web UI</li><li>录制回放不属于 <code>0.2.0</code>，延后到 <code>0.3.0</code></li></ul><p><code>0.2.0</code> 目前尚未正式发布。正式发布时将以 <strong>PyPI</strong> 作为公开安装入口；发布前会先完成一次 <strong>TestPyPI rehearsal</strong>，但 <code>TestPyPI</code> 不作为日常安装源。</p><h2 id="从哪里开始" tabindex="-1">从哪里开始 <a class="header-anchor" href="#从哪里开始" aria-label="Permalink to &quot;从哪里开始&quot;">​</a></h2><ul><li>想安装和运行：看 <a href="/install">安装与发布</a></li><li>想接 driver：看 <a href="/sdk">SDK 开发者指南</a></li><li>想理解 runtime：看 <a href="/core">Core 模块架构</a></li><li>想看 UI / host 方向：看 <a href="/ui">UI 模块架构</a> 和 <a href="/app">App 组合根</a></li><li>想查服务接口：看 <a href="/server-api">服务端 API 手册</a></li><li>想直接跳源码 API：看 <a href="/api">API 快速索引</a></li></ul><h2 id="三个正式入口" tabindex="-1">三个正式入口 <a class="header-anchor" href="#三个正式入口" aria-label="Permalink to &quot;三个正式入口&quot;">​</a></h2><ul><li>源码仓库：<a href="https://github.com/modlink-studio/ModLink-Studio" target="_blank" rel="noreferrer">github.com/modlink-studio/ModLink-Studio</a></li><li>文档站点：<a href="https://modlink-studio.github.io" target="_blank" rel="noreferrer">modlink-studio.github.io</a></li><li>正式发布渠道：PyPI（<code>0.2.0</code> 正式发布后生效）</li></ul>',9)])])}const m=t(d,[["render",l]]);export{P as __pageData,m as default};
